import{_ as e,o as s,c as l,ag as r}from"./chunks/framework.eQLvDOR_.js";const f=JSON.parse('{"title":"workflows-vs-agents","description":"","frontmatter":{"title":"workflows-vs-agents","concept":"Workflows vs Agents","concept_id":"workflows-vs-agents","aliases":["工作流 vs 智能体","agentic-systems"],"sources":["02_Library/Agent_Architecture/[Agent_Architecture] Building Effective AI Agents.md"],"related_concepts":["[[agentic-patterns]]","[[agent-harness-pattern]]"],"created_at":"2026-04-07","last_compiled":"2026-04-07"},"headers":[],"relativePath":"wiki/concepts/workflows-vs-agents.md","filePath":"wiki/concepts/workflows-vs-agents.md","lastUpdated":null}'),a={name:"wiki/concepts/workflows-vs-agents.md"};function o(n,t,i,g,d,c){return s(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="workflows-vs-agents-工作流-vs-智能体" tabindex="-1">Workflows vs Agents (工作流 vs 智能体) <a class="header-anchor" href="#workflows-vs-agents-工作流-vs-智能体" aria-label="Permalink to &quot;Workflows vs Agents (工作流 vs 智能体)&quot;">​</a></h1><h2 id="核心定义" tabindex="-1">核心定义 <a class="header-anchor" href="#核心定义" aria-label="Permalink to &quot;核心定义&quot;">​</a></h2><p>Anthropic 在其工程指南中，将所有此类系统统称为 <strong>Agentic Systems (智能体系统)</strong>，但针对架构设计做出了核心区分：</p><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;"><strong>Workflows (工作流)</strong></th><th style="text-align:left;"><strong>Agents (智能体)</strong></th></tr></thead><tbody><tr><td style="text-align:left;"><strong>控制流</strong></td><td style="text-align:left;">通过预定义的代码路径进行编排 (Hardcoded)</td><td style="text-align:left;">由 LLM 动态引导操作过程与工具使用</td></tr><tr><td style="text-align:left;"><strong>决策权</strong></td><td style="text-align:left;">逻辑逻辑在代码中，LLM 负责填充内容</td><td style="text-align:left;">LLM 维持对如何完成任务的控制权</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">目标明确、步骤固定的任务 (准确率高)</td><td style="text-align:left;">需要灵活性、具备模型驱动决策规模的任务</td></tr><tr><td style="text-align:left;"><strong>复杂度</strong></td><td style="text-align:left;">较低，易于调试和预测</td><td style="text-align:left;">较高，存在复合错误风险</td></tr></tbody></table><h2 id="架构选型原则" tabindex="-1">架构选型原则 <a class="header-anchor" href="#架构选型原则" aria-label="Permalink to &quot;架构选型原则&quot;">​</a></h2><ol><li><strong>简单优先</strong>：寻找最简单的解决方案，仅在必要时增加复杂度。</li><li><strong>权衡延迟与成本</strong>：Agentic Systems 通常用延迟和成本换取更好的任务表现。</li><li><strong>框架慎用</strong>：建议从直接使用 LLM API 开始，理解底层 Prompt 和响应，避免被框架的抽象掩盖调试细节。</li></ol><h2 id="关键见解" tabindex="-1">关键见解 <a class="header-anchor" href="#关键见解" aria-label="Permalink to &quot;关键见解&quot;">​</a></h2><blockquote><p>&quot;Success in the LLM space isn&#39;t about building the most sophisticated system. It&#39;s about building the <em>right</em> system for your needs.&quot;</p></blockquote><hr><h2 id="实践指南" tabindex="-1">实践指南 <a class="header-anchor" href="#实践指南" aria-label="Permalink to &quot;实践指南&quot;">​</a></h2><ul><li><strong>架构评分决策 (Decision Score)</strong>： <ul><li>如果任务是 100% 确定性的流程 -&gt; <strong>Workflow (100分)</strong>。</li><li>如果需要纠缠于模糊的自然语言指令 -&gt; <strong>Agent (100分)</strong>。</li><li>如果是 50/50 混合任务 -&gt; 优先使用 <strong>Modular Workflows</strong>，仅在最模糊的节点调用微型 Agent。</li></ul></li><li><strong>故障隔离</strong>：将 Agent 的决策层与 Workflow 的执行层物理分离。如果 Agent 下达了错误指令，Workflow 层的参数校验（Type-safe Schema）应能拦截非法的执行请求。</li></ul><hr><h2 id="参考链接" tabindex="-1">参考链接 <a class="header-anchor" href="#参考链接" aria-label="Permalink to &quot;参考链接&quot;">​</a></h2><ul><li><a href="/s/webclips/library/Agent_Architecture/Agent_Architecture - Building Effective AI Agents.html">[Agent_Architecture] Building Effective AI Agents</a></li></ul>',14)])])}const u=e(a,[["render",o]]);export{f as __pageData,u as default};
